     const MediaLightbox: React.FC<MediaLightboxProps> = (props) => {
       const { media, segmentSlotMode, ...restProps } = props;
       const isSegmentSlotMode = !!segmentSlotMode;
       const isVideo = media ? isVideoAny(media as any) : false;

       if (isSegmentSlotMode) {
         return <VideoLightbox media={media} segmentSlotMode={segmentSlotMode} {...restProps} />;
       }
       if (!media) {
         console.error('[MediaLightbox] ❌ No media prop provided!');
         return null;
